-- Base de datos ficticia para chatbot empresarial con RAG
-- Generada desde: informe materiales/redes, informe cosecha y mantenciones
-- Todos los datos son de prueba/anónimos.

DROP DATABASE IF EXISTS chatbot_transportes_rag;
CREATE DATABASE chatbot_transportes_rag CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE chatbot_transportes_rag;

SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE conductores (
  id_conductor INT PRIMARY KEY,
  nombre VARCHAR(120) NOT NULL UNIQUE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE equipos (
  id_equipo INT PRIMARY KEY,
  patente VARCHAR(20) NOT NULL UNIQUE,
  tipo_equipo VARCHAR(30) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE viajes_materiales_redes (
  id_viaje INT PRIMARY KEY,
  centro VARCHAR(100),
  orden_control_int INT,
  fecha_salida DATE,
  tipo_camion VARCHAR(30),
  origen VARCHAR(120),
  destino VARCHAR(120),
  id_conductor INT,
  conductor VARCHAR(120),
  id_tracto INT,
  patente_tracto VARCHAR(20),
  id_rampla INT,
  patente_rampla VARCHAR(20),
  guias VARCHAR(255),
  tarifa_flete DECIMAL(12,2),
  fuente VARCHAR(80) DEFAULT 'informe_materiales_redes',
  FOREIGN KEY (id_conductor) REFERENCES conductores(id_conductor),
  FOREIGN KEY (id_tracto) REFERENCES equipos(id_equipo),
  FOREIGN KEY (id_rampla) REFERENCES equipos(id_equipo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE viajes_cosecha (
  id_viaje INT PRIMARY KEY,
  centro VARCHAR(100),
  orden_control_int INT,
  fecha_salida DATE,
  tipo_camion VARCHAR(30),
  origen VARCHAR(120),
  destino VARCHAR(120),
  id_conductor INT,
  conductor VARCHAR(120),
  id_tracto INT,
  patente_tracto VARCHAR(20),
  id_rampla INT,
  patente_rampla VARCHAR(20),
  guias VARCHAR(255),
  tarifa_flete DECIMAL(12,2),
  fuente VARCHAR(80) DEFAULT 'informe_cosecha'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE mantenciones (
  id_mantencion INT PRIMARY KEY,
  id_equipo INT,
  patente VARCHAR(20),
  fecha DATE,
  tipo_mantencion VARCHAR(30),
  motivo VARCHAR(255),
  costo_repuestos DECIMAL(12,2),
  costo_mano_obra DECIMAL(12,2),
  costo_total DECIMAL(12,2),
  fuente VARCHAR(80) DEFAULT 'mantenciones_equipos',
  FOREIGN KEY (id_equipo) REFERENCES equipos(id_equipo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE documentos_rag (
  id_documento INT AUTO_INCREMENT PRIMARY KEY,
  tipo_documento VARCHAR(80),
  referencia_tabla VARCHAR(80),
  referencia_id INT,
  contenido TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;








SET FOREIGN_KEY_CHECKS = 1;

-- Consultas de verificación
SELECT COUNT(*) AS total_materiales_redes FROM viajes_materiales_redes;
SELECT COUNT(*) AS total_cosecha FROM viajes_cosecha;
SELECT COUNT(*) AS total_mantenciones FROM mantenciones;
SELECT COUNT(*) AS total_documentos_rag FROM documentos_rag;
